messages.content:
{
  "root_causes": [
    {
      "type": "configuration_mismatch",
      "cause": "GigabitEthernet0/0/1 on R2 is manually configured for 100 Mbps, half-duplex with auto-negotiation disabled while R1 is set to auto-negotiation — causing a duplex/speed negotiation mismatch and resulting input errors.",
      "evidence": [
        "R2 running-config: \"Cisco-IOS-XE-ethernet:speed\": { \"value-100\": [ null ] }, \"Cisco-IOS-XE-ethernet:duplex\": \"half\", \"Cisco-IOS-XE-ethernet:negotiation\": { \"auto\": false } (get_running_config:router2)",
        "R1 running-config: \"Cisco-IOS-XE-ethernet:negotiation\": { \"auto\": true } on interface GigabitEthernet0/0/1 (get_running_config:router1)",
        "R1 interface status: admin_state=up, oper_state=up, speed=102400000, input_errors=57 (get_interface_status:router1:GigabitEthernet0/0/1)",
        "R2 interface status: admin_state=up, oper_state=up, speed=102400000, input_errors=59 (get_interface_status:router2:GigabitEthernet0/0/1)",
        "Interface duplex not reported by status (duplex=null), consistent with one side forced and the other auto-negotiating (get_interface_status outputs)"
      ],
      "confidence": 0.92
    }
  ],
  "missing_info": []
}

{
  "intent": "check_and_fix",
  "intent_description": "Input errors on GigabitEthernet0/0/1 on router2 caused by a speed/duplex negotiation mismatch with router1; restore link-layer health by configuring router2's GigabitEthernet0/0/1 to use auto-negotiation (speed/duplex auto).",
  "target": "router2",
  "needs_fix": true,
  "plan": {
    "problem": "GigabitEthernet0/0/1 on router2 is manually configured for 100 Mbps, half-duplex with auto-negotiation disabled while router1 is set to auto-negotiation, causing input errors and degraded link-layer performance.",
    "fix_summary": "Enable auto-negotiation on router2 GigabitEthernet0/0/1 so speed and duplex are negotiated automatically to match router1.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "set_interface_negotiation",
        "target": "GigabitEthernet0/0/1",
        "parameters": [
          "negotiation=auto"
        ]
      }
    ]
  }
}

